        protected void btnCancel_OnClick(object sender, EventArgs e)
        {
            this.Session["DeleteMsg"] = null;
            if (this.pagename.ToString().ToLower().Trim() == "report")
            {
                base.Response.Redirect(string.Concat(this.strSitepath, "common/report.aspx"));
                return;
            }
            base.Response.Redirect(string.Concat(this.strSitepath, "jobs/jobs_view.aspx"));
        }

        public void btnExport_New_OnClick(object sender, EventArgs e)
        {
            this.export = "true";
            this.Session["DeleteMsg"] = null;
            if (this.rdodetail.Checked || this.rdosummary.Checked)
            {
                string value = this.hdnInnerHtml.Value;
                string str = "Job_List.xls";
                base.Response.Cache.SetExpires(DateTime.Now.AddSeconds(1));
                base.Response.Clear();
                base.Response.AppendHeader("content-disposition", string.Concat("attachment;filename=\"", str, "\""));
                base.Response.Charset = "";
                base.Response.Cache.SetCacheability(HttpCacheability.NoCache);
                base.Response.ContentType = "application/vnd.ms-excel";
                this.EnableViewState = false;
                base.Response.Write("\r\n");
                base.Response.Write(value);
                base.Response.End();
                return;
            }
            int num = 0;
            for (int i = 0; i < this.chkColumns.Items.Count; i++)
            {
                if (this.chkColumns.Items[i].Selected)
                {
                    num = 1;
                }
            }
            if (num != 1)
            {
                this.spnError.Visible = true;
                return;
            }
            DataSet estimateData = this.GetEstimateData(0);
            DataTable item = estimateData.Tables[0];
            if (item != null)
            {
                string empty = string.Empty;
                foreach (DataRow row in item.Rows)
                {
                    if (row.Table.Columns.Contains("CompletionDate"))
                    {
                        row["CompletionDate"] = this.objJava.Eprint_return_Date_Before_View(row["CompletionDate"].ToString(), this.CompanyID, this.UserID, false);
                    }
                    if (row.Table.Columns.Contains("CreatedDate"))
                    {
                        row["CreatedDate"] = this.objJava.Eprint_return_Date_Before_View(row["CreatedDate"].ToString(), this.CompanyID, this.UserID, false);
                    }
                    if (row.Table.Columns.Contains("ItemCreatedOn"))
                    {
                        row["ItemCreatedOn"] = this.objJava.Eprint_return_Date_Before_View(row["ItemCreatedOn"].ToString(), this.CompanyID, this.UserID, false);
                    }
                    if (row.Table.Columns.Contains("DeliveryDate"))
                    {
                        row["DeliveryDate"] = this.objJava.Eprint_return_Date_Before_View(row["DeliveryDate"].ToString(), this.CompanyID, this.UserID, false);
                    }
                    if (row.Table.Columns.Contains("ActualDeliveryDate"))
                    {
                        row["ActualDeliveryDate"] = this.objJava.Eprint_return_Date_Before_View(row["ActualDeliveryDate"].ToString(), this.CompanyID, this.UserID, false);
                    }
                    if (row.Table.Columns.Contains("ActivityNotes"))
                    {
                        string str1 = row["ActivityNotes"].ToString().Replace("¶", " ");
                        this.lblActivity.Text = base.Server.HtmlDecode(str1);
                        row["ActivityNotes"] = this.lblActivity.Text.ToString().Replace("<br />", " ").Replace("<br/>", " ").Replace("&lt;br/&gt;", " ").Replace("&lt;br /&gt;", " ");
                    }
                    if (row.Table.Columns.Contains("ItemTitle"))
                    {
                        string str2 = row["ItemTitle"].ToString().Replace("<br/>", "<br />");
                        this.lblItemTitle.Text = base.Server.HtmlDecode(base.SpecialDecode(str2));
                        row["ItemTitle"] = this.lblItemTitle.Text;
                    }
                    if (row.Table.Columns.Contains("commissionamount"))
                    {
                        item.Columns["commissionamount"].ColumnName = string.Concat("Commission (", this.objJava.GetCurrencyinRequiredFormate("", true), ")");
                    }
                    if (row.Table.Columns.Contains("Taxvalue"))
                    {
                        item.Columns["Taxvalue"].ColumnName = string.Concat("Total Tax Price (", this.objJava.GetCurrencyinRequiredFormate("", true), ")");
                    }
                    if (!row.Table.Columns.Contains("commissionpercentage"))
                    {
                        continue;
                    }
                    item.Columns["CommissionPercentage"].ColumnName = "Commission (%)";
                }
            }
            DataTable dataTable = estimateData.Tables[0];
            if (this.chkColumns.Items[67].Selected)
            {
                DataColumn dataColumn = new DataColumn();
                dataTable.Columns.Add("EventDate", typeof(string));
                foreach (DataRow dataRow in estimateData.Tables[0].Rows)
                {
                    string str3 = this.objJava.Eprint_return_Date_Before_View(dataRow["Eventstartdate"].ToString(), this.CompanyID, this.UserID, false);
                    string str4 = this.objJava.Eprint_return_Date_Before_View(dataRow["Eventenddate"].ToString(), this.CompanyID, this.UserID, false);
                    if (!(str3 != "") || !(str4 != ""))
                    {
                        continue;
                    }
                    dataRow["EventDate"] = string.Concat(str3, "-", str4);
                }
                estimateData.Tables[0].Columns.Remove("Eventstartdate");
                estimateData.Tables[0].Columns.Remove("Eventenddate");
            }
