                linkButton2.Font.Bold = false;
                linkButton3.Font.Bold = false;
                linkButton.Font.Bold = false;
            }
            LinkButton linkButton5 = (LinkButton)usrPagingID.FindControl("lnkstart");
            LinkButton linkButton6 = (LinkButton)usrPagingID.FindControl("lnkPrev");
            LinkButton linkButton7 = (LinkButton)usrPagingID.FindControl("lnkNext");
            LinkButton linkButton8 = (LinkButton)usrPagingID.FindControl("lnkEnd");
            if (this.txt1.Text != "")
            {
                if (Convert.ToInt16(this.txt1.Text) >= 4)
                {
                    linkButton5.Enabled = true;
                    linkButton6.Enabled = true;
                }
                if (Convert.ToInt16(this.txt1.Text) >= 1)
                {
                    linkButton.Enabled = true;
                }
            }
            //if (this.GridEstReport.PageIndex == 1 || this.GridEstReport.PageIndex == 0)
            //{
            //    linkButton5.Enabled = false;
            //    linkButton6.Enabled = false;
            //}
            if (linkButton5.Enabled)
            {
                linkButton5.OnClientClick = "javascript:showWaitMessage();";
            }
            else
            {
                linkButton5.OnClientClick = "javascript:Disablelnk();";
            }
            if (linkButton6.Enabled)
            {
                linkButton6.OnClientClick = "javascript:showWaitMessage();";
            }
            else
            {
                linkButton6.OnClientClick = "javascript:Disablelnk();";
            }
            if (linkButton7.Enabled)
            {
                linkButton7.OnClientClick = "javascript:showWaitMessage();";
            }
            else
            {
                linkButton7.OnClientClick = "javascript:Disablelnk();";
            }
            if (!linkButton8.Enabled)
            {
                linkButton8.OnClientClick = "javascript:Disablelnk();";
                return;
            }
            linkButton8.OnClientClick = "javascript:showWaitMessage();";
        }

        private bool Check_ItemSelected()
        {
            bool flag;
            string[] strArrays = new string[] { "jobvalue", "itemtitle", "statusid", "description", "artwork", "colour", "size", "material", "delivery", "finishing", "notes", "instructions", "proofs", "packing", "subtotal", "costexmarkup", "grossprofitprice", "grossprofitpercentage", "itemquantity", "customercode", "packunit", "costprice", "suppliername", "producttitle", "productcode", "productcatagory", "productwidth", "productheight", "productlength", "productweight", "productdimension", "qtydescription1", "commissionamount", "commissionpercentage", "taxvalue", "costper1000", "subtotalper1000", "itemcreatedon"
            , "itemextax", "iteminctax"};
            string[] strArrays1 = strArrays;
            foreach (ListItem item in this.chkColumns.Items)
            {
                string[] strArrays2 = strArrays1;
                int num = 0;
                while (num < (int)strArrays2.Length)
                {
                    string str = strArrays2[num];
                    if (!item.Selected || !(item.Value.ToLower() == str))
                    {
                        num++;
                    }
                    else
                    {
                        flag = true;
                        return flag;
                    }
                }
            }
            IEnumerator enumerator = this.ddlEstimateType.Items.GetEnumerator();
            try
            {
                while (enumerator.MoveNext())
                {
                    CheckBoxList checkBoxList = (CheckBoxList)((RadComboBoxItem)enumerator.Current).FindControl("chkEstType");
                    IEnumerator enumerator1 = checkBoxList.Items.GetEnumerator();
                    try
                    {
                        while (enumerator1.MoveNext())
                        {
                            if (!((ListItem)enumerator1.Current).Selected)
                            {
                                continue;
                            }
                            flag = true;
                            return flag;
                        }
                    }
                    finally
                    {
                        IDisposable disposable = enumerator1 as IDisposable;
                        if (disposable != null)
                        {
                            disposable.Dispose();
                        }
                    }
                }
                goto Label1;
            }
            finally
            {
                IDisposable disposable1 = enumerator as IDisposable;
                if (disposable1 != null)
                {
                    disposable1.Dispose();
                }
            }
            return flag;
        Label1:
            if (this.txtFreetext.Text.Trim() != "" && (this.chkfreetext.Items[2].Selected || this.chkfreetext.Items[11].Selected || this.chkfreetext.Items[12].Selected || this.chkfreetext.Items[13].Selected || this.chkfreetext.Items[14].Selected || this.chkfreetext.Items[15].Selected))
            {
                return true;
            }
            if (this.ddlEstimateRange.SelectedIndex != 0)
            {
                return true;
            }
            if (this.chkconvertedoption.Checked)
            {
                return true;
            }
            for (int i = 0; i < this.lstStatus.Items.Count; i++)
            {
                if (this.lstStatus.Items[i].Checked)
                {
                    return true;
                }
            }
            if (this.ddlInvoiceStatus.SelectedIndex != 0)
            {
                return true;
            }
            if (this.ddlShowJobs.SelectedIndex != 0)
            {
                return true;
            }
            return false;
        }

        public string checkdateformat()
        {
            if (this.DateFormat == "mm/dd/yyyy")
            {
                return "1";
            }
            return "2";
        }

        public string CurrentFiscalYear()
        {
            DataTable dataTable = SettingsBasePage.settings_regionalsettings_select(this.CompanyID);
            DateTime dateTime = Convert.ToDateTime(dataTable.Rows[0]["FisCalFrom"]);
            DateTime dateTime1 = Convert.ToDateTime(dataTable.Rows[0]["FisCalTo"]);
            string str = string.Concat(dateTime.ToString(), ",", dateTime1.ToString());
            return str;
        }

        public string CurrentMonth()
        {
            DataTable dataTable = SettingsBasePage.settings_regionalsettings_select(this.CompanyID);
            DateTime dateTime = Convert.ToDateTime(dataTable.Rows[0]["FisCalFrom"]);
            DateTime[] dateTimeArray = new DateTime[] { new DateTime(dateTime.Year, dateTime.Month, 1), default(DateTime) };
            DateTime dateTime1 = new DateTime(dateTime.Year, dateTime.Month, 1);
            DateTime dateTime2 = dateTime1.AddMonths(1);
            dateTimeArray[1] = dateTime2.AddDays(-1);
            string str = string.Concat(dateTimeArray[0].ToString(), ",", dateTimeArray[1].ToString());
            return str;
        }

