            DataTable dataTable = this.GetListItem();
            int count = dataTable.Rows.Count;
            string empty = string.Empty;
            string str = string.Empty;
            string empty1 = string.Empty;
            for (int i = 0; i < count; i++)
            {
                empty = dataTable.Rows[i]["Value"].ToString();
                str = dataTable.Rows[i]["ID"].ToString();
                object[] objArray = new object[] { "<a href=\"javascript:void(0)\" id=\"alst\" style=\"text-decoration:none;color:Black; \" onclick=\"getSelectedItem(' ", empty, "','", i, "','", str, "','anchor');\">", empty, "</a>" };
